"""
Binance Futures Testnet Connector (v3 — dirapiin, logic sama seperti v2)
"""
import hmac
import hashlib
import time
import requests
from urllib.parse import urlencode


class BinanceTestnet:
    def __init__(self, api_key, api_secret, base_url):
        self.api_key = api_key
        self.api_secret = api_secret
        self.base_url = base_url.rstrip('/')
        self.session = requests.Session()
        self.session.headers.update({'X-MBX-APIKEY': self.api_key})

    def _sign(self, params):
        query = urlencode(params)
        sig = hmac.new(self.api_secret.encode(), query.encode(), hashlib.sha256).hexdigest()
        params['signature'] = sig
        return params

    def _ts(self):
        return int(time.time() * 1000)

    def _get(self, path, params=None, signed=False):
        if params is None:
            params = {}
        if signed:
            params['timestamp'] = self._ts()
            params = self._sign(params)
        try:
            r = self.session.get(f"{self.base_url}{path}", params=params, timeout=30)
            if r.status_code == 200:
                return r.json()
            return {'error': r.status_code, 'msg': r.text[:200]}
        except Exception as e:
            return {'error': str(e)}

    def _post(self, path, params=None):
        if params is None:
            params = {}
        params['timestamp'] = self._ts()
        params = self._sign(params)
        try:
            r = self.session.post(f"{self.base_url}{path}", params=params, timeout=30)
            if r.status_code == 200:
                return r.json()
            return {'error': r.status_code, 'msg': r.text[:200]}
        except Exception as e:
            return {'error': str(e)}

    def _delete(self, path, params=None):
        if params is None:
            params = {}
        params['timestamp'] = self._ts()
        params = self._sign(params)
        try:
            r = self.session.delete(f"{self.base_url}{path}", params=params, timeout=30)
            if r.status_code == 200:
                return r.json()
            return {'error': r.status_code, 'msg': r.text[:200]}
        except Exception as e:
            return {'error': str(e)}

    # ========== PUBLIC ==========
    def get_price(self, symbol):
        data = self._get('/fapi/v1/ticker/price', {'symbol': symbol})
        if 'error' not in data:
            return float(data['price'])
        return None

    def _parse_candles(self, data):
        """Parse raw kline data ke format standard."""
        candles = []
        for c in data:
            candles.append({
                'time': c[0],
                'open': float(c[1]),
                'high': float(c[2]),
                'low': float(c[3]),
                'close': float(c[4]),
                'volume': float(c[5]),
                'quote_vol': float(c[7]),
                'trades': int(c[8]),
                'taker_buy_vol': float(c[9]),
                'taker_buy_quote': float(c[10]),
            })
        return candles

    def get_candles(self, symbol, interval='15m', limit=100):
        """
        Fetch klines dengan auto-pagination kalau limit > 1500.
        Binance max 1500 per request, tapi bisa di-paginate pakai endTime.
        Max range 200 hari.
        """
        BATCH = 1500
        if limit <= BATCH:
            data = self._get('/fapi/v1/klines', {
                'symbol': symbol, 'interval': interval, 'limit': limit
            })
            return self._parse_candles(data) if isinstance(data, list) else []

        # Pagination: ambil dari terbaru ke belakang
        all_candles = []
        end_time = None  # None = latest
        remaining = limit

        while remaining > 0:
            batch_size = min(remaining, BATCH)
            params = {'symbol': symbol, 'interval': interval, 'limit': batch_size}
            if end_time is not None:
                params['endTime'] = end_time - 1  # -1ms biar gak duplikat

            data = self._get('/fapi/v1/klines', params)
            if not isinstance(data, list) or len(data) == 0:
                break

            batch = self._parse_candles(data)
            all_candles = batch + all_candles  # prepend (chronologis)
            end_time = batch[0]['time']
            remaining -= len(batch)

            # Kalau batch kurang dari request, artinya udah mentok (no more data)
            if len(batch) < batch_size:
                break

            import time
            time.sleep(0.2)  # rate limit buffer

        return all_candles

    def get_agg_trades(self, symbol, limit=500):
        data = self._get('/fapi/v1/aggTrades', {'symbol': symbol, 'limit': limit})
        if isinstance(data, list):
            trades = []
            for t in data:
                trades.append({
                    'price': float(t['p']),
                    'qty': float(t['q']),
                    'time': t['T'],
                    'is_buyer_maker': t['m'],  # True = seller initiated (market sell)
                })
            return trades
        return []

    def get_depth(self, symbol, limit=20):
        data = self._get('/fapi/v1/depth', {'symbol': symbol, 'limit': limit})
        if 'bids' in data:
            return {
                'bids': [[float(p), float(q)] for p, q in data['bids']],
                'asks': [[float(p), float(q)] for p, q in data['asks']],
                'time': data.get('lastUpdateId', 0),
            }
        return None

    def get_exchange_info(self, symbol=None):
        data = self._get('/fapi/v1/exchangeInfo')
        if 'symbols' in data:
            if symbol:
                for s in data['symbols']:
                    if s['symbol'] == symbol:
                        return s
            return data['symbols']
        return data

    # ========== SIGNED ==========
    def get_account(self):
        return self._get('/fapi/v2/account', signed=True)

    def get_balance(self):
        data = self._get('/fapi/v2/balance', signed=True)
        if isinstance(data, list):
            for b in data:
                if b['asset'] == 'USDT':
                    return {
                        'balance': float(b['balance']),
                        'available': float(b['availableBalance']),
                        'unrealized': float(b.get('crossUnPnl', 0)),
                    }
        return None

    def get_positions(self):
        data = self._get('/fapi/v2/positionRisk', signed=True)
        if isinstance(data, list):
            return [p for p in data if float(p.get('positionAmt', 0)) != 0]
        return []

    def get_open_orders(self, symbol=None):
        params = {}
        if symbol:
            params['symbol'] = symbol
        data = self._get('/fapi/v1/openOrders', params, signed=True)
        if isinstance(data, list):
            return data
        return []

