    def set_leverage(self, symbol, leverage):
        return self._post('/fapi/v1/leverage', {'symbol': symbol, 'leverage': leverage})

    def set_position_mode(self, dual=True):
        mode = 'true' if dual else 'false'
        return self._post('/fapi/v1/positionSide/dual', {'dualSidePosition': mode})

    def market_order(self, symbol, side, quantity, reduce_only=False):
        params = {
            'symbol': symbol, 'side': side.upper(), 'type': 'MARKET', 'quantity': quantity,
        }
        if reduce_only:
            params['reduceOnly'] = 'true'
        return self._post('/fapi/v1/order', params)

    def limit_order(self, symbol, side, quantity, price, time_in_force='GTC'):
        return self._post('/fapi/v1/order', {
            'symbol': symbol, 'side': side.upper(), 'type': 'LIMIT',
            'quantity': quantity, 'price': price, 'timeInForce': time_in_force,
        })

    def stop_market(self, symbol, side, quantity, stop_price):
        """STOP_MARKET via Algo Order API (dibutuhkan testnet sejak Des 2025)."""
        return self._algo_order(symbol, 'STOP_MARKET', side, quantity, stop_price)

    def take_profit_market(self, symbol, side, quantity, stop_price):
        """TAKE_PROFIT_MARKET via Algo Order API."""
        return self._algo_order(symbol, 'TAKE_PROFIT_MARKET', side, quantity, stop_price)

    def _algo_order(self, symbol, order_type, side, quantity, trigger_price):
        """Algo order (CONDITIONAL) via POST /fapi/v1/algoOrder. reduceOnly=true supaya cuma close posisi."""
        return self._post('/fapi/v1/algoOrder', {
            'symbol': symbol,
            'side': side.upper(),
            'type': order_type,
            'algoType': 'CONDITIONAL',
            'triggerPrice': str(trigger_price),
            'quantity': str(quantity),
            'workingType': 'MARK_PRICE',
            'reduceOnly': 'true',
        })

    def cancel_algo_order(self, symbol, algo_id):
        return self._delete('/fapi/v1/algoOrder', {'symbol': symbol, 'algoId': algo_id})

    def cancel_all_algo_orders(self, symbol, algo_ids=None):
        """Cancel algo orders. Testnet gak ada list endpoint jadi butuh tracked IDs."""
        results = []
        if algo_ids:
            for aid in algo_ids:
                results.append(self.cancel_algo_order(symbol, aid))
        return results

    def cancel_order(self, symbol, order_id):
        return self._delete('/fapi/v1/order', {'symbol': symbol, 'orderId': order_id})

    def cancel_all_orders(self, symbol, algo_ids=None):
        """Cancel semua regular order + algo order buat 1 symbol."""
        regular = self._delete('/fapi/v1/allOpenOrders', {'symbol': symbol})
        self.cancel_all_algo_orders(symbol, algo_ids)
        return regular
